module gray_decoder (
        gin, 
        bout
);

parameter width = 6;

input  [width-1 : 0] gin;
output [width-1 : 0] bout;

reg    [width-1 : 0] bval;
integer i;
assign bout = bval;

always @(gin)
begin
    bval[width-1] = gin[width-1];
    if (width > 1)
    begin
        for (i=width-2; i >= 0; i=i-1)
            bval[i] = bval[i+1] ^ gin[i];
    end
end

endmodule
